import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext'; // Ensure theme sync
import toast from 'react-hot-toast';
import { Eye, EyeOff, UserPlus, Zap } from 'lucide-react';

const RegisterPage = () => {
  const { register } = useAuth();
  const { isDarkMode } = useTheme(); // Consuming the dual-theme state
  const navigate = useNavigate();

  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  // Dynamic colors for Webkit Autofill based on theme
  const dynamicAutofillBg = isDarkMode ? '#000000' : '#ffffff';
  const dynamicAutofillText = isDarkMode ? '#ffffff' : '#000000';

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password || !formData.confirmPassword) {
      return toast.error('INPUT_REQUIRED: Please fill in all fields');
    }

    if (formData.password !== formData.confirmPassword) {
      return toast.error('SECURITY_ERROR: Passwords do not match');
    }

    if (formData.password.length < 6) {
      return toast.error('POLICY_ERROR: Master Key must be at least 6 characters');
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('NODE_INITIALIZED: Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'REGISTRATION_FAILED: Network error.');
    } finally {
      setLoading(false);
    }
  };

  /* ───────── Dynamic Styles ───────── */
  const inputStyle = (fieldId, extra = {}) => ({
    width: '100%',
    boxSizing: 'border-box',
    // Forces the autofill box to match the theme background perfectly
    WebkitBoxShadow: `0 0 0px 1000px ${dynamicAutofillBg} inset`,
    WebkitTextFillColor: dynamicAutofillText,
    caretColor: 'var(--accent-primary)',
    border: `1px solid ${focused === fieldId ? 'var(--accent-primary)' : 'var(--surface-border)'}`,
    background: 'var(--bg-main)',
    color: 'var(--text-primary)',
    padding: '0.8rem 1rem',
    borderRadius: '12px',
    outline: 'none',
    transition: 'all 0.2s ease',
    ...extra,
  });

  const labelStyle = (field) => ({
    display: 'block', 
    fontSize: '0.65rem', 
    fontWeight: 800,
    textTransform: 'uppercase', 
    letterSpacing: '0.15em',
    color: focused === field ? 'var(--accent-primary)' : 'var(--text-muted)',
    marginBottom: '0.5rem', 
    transition: 'color 0.2s ease',
  });

  return (
    <div style={pageWrapper}>
      {/* Background Ambience */}
      <div aria-hidden="true" style={glowTopLeft} />
      <div aria-hidden="true" style={glowBottomRight} />

      {/* Register Card */}
      <div className="reveal-node" style={cardStyle}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '2rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '1rem' }}>
            <div style={iconContainer}>
              <UserPlus size={22} color="var(--accent-primary)" />
            </div>
          </div>
          <h1 style={titleStyle}>Initialize Node</h1>
          <p style={subtitleStyle}>Create your master credentials</p>
        </div>

        <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1.2rem' }}>
          {/* Name Field */}
          <div>
            <label htmlFor="name" style={labelStyle('name')}>Full Name</label>
            <input
              id="name"
              type="text"
              placeholder="Operator Name"
              value={formData.name}
              onChange={e => setFormData({...formData, name: e.target.value})}
              onFocus={() => setFocused('name')}
              onBlur={() => setFocused(null)}
              autoComplete="name"
              style={inputStyle('name')}
            />
          </div>

          {/* Email Field */}
          <div>
            <label htmlFor="email" style={labelStyle('email')}>Email Address</label>
            <input
              id="email"
              type="email"
              placeholder="operator@finify.ai"
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
              onFocus={() => setFocused('email')}
              onBlur={() => setFocused(null)}
              autoComplete="email"
              style={inputStyle('email')}
            />
          </div>

          {/* Password Field */}
          <div>
            <label htmlFor="password" style={labelStyle('password')}>Master Key</label>
            <div style={{ position: 'relative' }}>
              <input
                id="password"
                type={showPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
                onFocus={() => setFocused('password')}
                onBlur={() => setFocused(null)}
                autoComplete="new-password"
                style={inputStyle('password', { paddingRight: '3rem' })}
              />
              <button type="button" onClick={() => setShowPassword(!showPassword)} style={eyeBtnStyle}>
                {showPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          {/* Confirm Password Field */}
          <div>
            <label htmlFor="confirmPassword" style={labelStyle('confirmPassword')}>Confirm Master Key</label>
            <div style={{ position: 'relative' }}>
              <input
                id="confirmPassword"
                type={showConfirmPassword ? 'text' : 'password'}
                placeholder="••••••••"
                value={formData.confirmPassword}
                onChange={e => setFormData({...formData, confirmPassword: e.target.value})}
                onFocus={() => setFocused('confirmPassword')}
                onBlur={() => setFocused(null)}
                autoComplete="new-password"
                style={inputStyle('confirmPassword', { paddingRight: '3rem' })}
              />
              <button type="button" onClick={() => setShowConfirmPassword(!showConfirmPassword)} style={eyeBtnStyle}>
                {showConfirmPassword ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          <button type="submit" className="cyber-btn" disabled={loading} style={{ marginTop: '0.5rem' }}>
            {loading ? <Zap size={16} className="animate-pulse" /> : 'DEPLOY_NODE'}
          </button>
        </form>

        <div style={footerStyle}>
          <p style={footerText}>
            Existing Operator?{' '}
            <Link to="/login" style={linkStyle}>Log in</Link>
          </p>
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────── Styles ─────────────────────────────── */

const pageWrapper = {
  flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center',
  padding: '2rem 1rem', background: 'var(--bg-main)', minHeight: '100vh', width: '100vw'
};

const cardStyle = {
  width: '100%', maxWidth: '420px', padding: '2.5rem', borderRadius: '24px',
  background: 'var(--surface-glass)', border: '1px solid var(--surface-border)',
  boxShadow: 'var(--shadow-elevated)', backdropFilter: 'blur(20px)', zIndex: 1
};

const titleStyle = { fontSize: '1.6rem', fontWeight: 900, color: 'var(--text-primary)', margin: '0 0 0.5rem' };
const subtitleStyle = { fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '0.2em', color: 'var(--text-muted)', margin: 0 };

const iconContainer = {
  width: '50px', height: '50px', borderRadius: '15px', background: 'var(--accent-muted)',
  border: '1px solid var(--accent-primary)', display: 'flex', alignItems: 'center', justifyContent: 'center',
  boxShadow: '0 0 20px var(--accent-glow)'
};

const eyeBtnStyle = {
  position: 'absolute', right: '1rem', top: '50%', transform: 'translateY(-50%)',
  background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer'
};

